#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <fcntl.h>

// Structure to represent a file handle in the pool
struct file_handle {
    int fd;
};

// Pool of file handles
static struct file_handle *pool = NULL;

// Function to add a new file handle to the pool
void add_file_handle(int fd) {
    // Allocate memory for the new file handle
    struct file_handle *new_handle = malloc(sizeof(struct file_handle));
    if (!new_handle) {
        perror("malloc");
        return;
    }

    // Initialize the new file handle with the given fd
    new_handle->fd = fd;

    // Add the new file handle to the pool
    struct file_handle **ptr = &pool;
    while (*ptr) {
        ptr = &(*ptr)->next;
    }
    *ptr = new_handle;
}

// Function to remove a file handle from the pool
void remove_file_handle(int fd) {
    // Find the file handle in the pool that corresponds to the given fd
    struct file_handle **ptr = &pool;
    while (*ptr && (*ptr)->fd != fd) {
        ptr = &(*ptr)->next;
    }

    // If the file handle was found, remove it from the pool and free its memory
    if (*ptr) {
        struct file_handle *tmp = *ptr;
        *ptr = tmp->next;
        free(tmp);
    }
}

// Function to clean up all resources in the pool
void cleanup() {
    // Free all file handles in the pool
    while (pool) {
        struct file_handle *tmp = pool;
        pool = tmp->next;
        free(tmp);
    }
}